import { cookies } from "next/headers";
import { createHmac, timingSafeEqual } from "node:crypto";

export type SessionRole = "owner" | "admin" | "agent" | "viewer";

export type SessionData = {
  userId: string;
  name: string;
  email: string;
  workspaceId: string;
  role: SessionRole;
};

const SESSION_COOKIE = "vaa_demo_session";

export const DEFAULT_SESSION: SessionData = {
  userId: "demo-user",
  name: "Demo User",
  email: "demo@voice-action.local",
  workspaceId: "default-workspace",
  role: "owner",
};

type ParsedSessionCookie = {
  session: SessionData;
  signed: boolean;
};

const SESSION_SIGNATURE_PREFIX = "v1";

function normalizeSession(raw: Partial<SessionData>): SessionData | null {
  const parsedRole: SessionRole | null =
    raw.role === "owner" || raw.role === "admin" || raw.role === "agent" || raw.role === "viewer"
      ? raw.role
      : null;
  if (!raw.userId || !raw.workspaceId || !parsedRole) {
    return null;
  }

  return {
    ...DEFAULT_SESSION,
    ...raw,
    role: parsedRole,
  };
}

function getSessionSigningSecret() {
  return process.env.SESSION_SIGNING_SECRET?.trim() || null;
}

function requireSignedSessionInProd() {
  const raw = process.env.REQUIRE_SIGNED_SESSION_IN_PROD?.trim().toLowerCase();
  if (!raw) {
    return true;
  }
  return ["1", "true", "yes", "on"].includes(raw);
}

function signPayload(payloadBase64Url: string, secret: string) {
  const hmac = createHmac("sha256", secret);
  hmac.update(`${SESSION_SIGNATURE_PREFIX}.${payloadBase64Url}`);
  return hmac.digest("base64url");
}

function verifySignature(payloadBase64Url: string, signatureBase64Url: string, secret: string) {
  const expected = signPayload(payloadBase64Url, secret);
  const expectedBuffer = Buffer.from(expected, "utf8");
  const providedBuffer = Buffer.from(signatureBase64Url, "utf8");

  if (expectedBuffer.length !== providedBuffer.length) {
    return false;
  }

  return timingSafeEqual(expectedBuffer, providedBuffer);
}

function decodeSession(raw: string): ParsedSessionCookie | null {
  try {
    const secret = getSessionSigningSecret();
    const requireSigned = process.env.NODE_ENV === "production" && requireSignedSessionInProd();
    if (requireSigned && !secret) {
      return null;
    }
    const [payloadBase64Url, signatureBase64Url, ...rest] = raw.split(".");
    if (!payloadBase64Url || rest.length > 0) {
      return null;
    }

    const signed = Boolean(signatureBase64Url);
    if (requireSigned && !signed) {
      return null;
    }
    if (secret) {
      if (!signed || !signatureBase64Url) {
        return null;
      }
      if (!verifySignature(payloadBase64Url, signatureBase64Url, secret)) {
        return null;
      }
    }

    const parsed = JSON.parse(Buffer.from(payloadBase64Url, "base64url").toString("utf8")) as Partial<SessionData>;
    const session = normalizeSession(parsed);
    if (!session) {
      return null;
    }

    return {
      session,
      signed,
    };
  } catch {
    return null;
  }
}

function encodeSession(session: SessionData) {
  const payloadBase64Url = Buffer.from(JSON.stringify(session), "utf8").toString("base64url");
  const secret = getSessionSigningSecret();
  const requireSigned = process.env.NODE_ENV === "production" && requireSignedSessionInProd();
  if (requireSigned && !secret) {
    throw new Error(
      "SESSION_SIGNING_SECRET is required when REQUIRE_SIGNED_SESSION_IN_PROD=true.",
    );
  }
  if (!secret) {
    return payloadBase64Url;
  }

  const signatureBase64Url = signPayload(payloadBase64Url, secret);
  return `${payloadBase64Url}.${signatureBase64Url}`;
}

export function parseSessionCookieValue(raw?: string | null) {
  if (!raw) {
    return null;
  }

  return decodeSession(raw);
}

export function getSessionCookieName() {
  return SESSION_COOKIE;
}

export async function getServerSession() {
  const cookieStore = await cookies();
  const value = cookieStore.get(SESSION_COOKIE)?.value;
  if (!value) {
    return DEFAULT_SESSION;
  }

  return decodeSession(value)?.session ?? DEFAULT_SESSION;
}

export async function setServerSession(session: Partial<SessionData>) {
  const cookieStore = await cookies();
  const merged: SessionData = {
    ...DEFAULT_SESSION,
    ...session,
  };

  cookieStore.set({
    name: SESSION_COOKIE,
    value: encodeSession(merged),
    httpOnly: true,
    sameSite: "strict",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: 60 * 60 * 24 * 14,
  });

  return merged;
}

export async function clearServerSession() {
  const cookieStore = await cookies();
  cookieStore.delete(SESSION_COOKIE);
}

export function maskEmail(email: string) {
  const [local, domain] = email.split("@");
  if (!local || !domain) {
    return "hidden";
  }

  if (local.length <= 2) {
    return `${local[0] ?? "*"}*@${domain}`;
  }

  return `${local.slice(0, 2)}***@${domain}`;
}

lib/idempotency.ts.source:
import { getRuntimeStateAdapter } from "@/lib/runtime-state";

const DEFAULT_RESPONSE_TTL_SECONDS = 60 * 60 * 24;
const DEFAULT_LOCK_TTL_SECONDS = 60;

export type StoredIdempotentResponse = {
  status: number;
  body: unknown;
  headers?: Record<string, string>;
  storedAt: string;
};

function sanitizeSegment(value: string) {
  return value.replace(/[^a-zA-Z0-9:_-]/g, "_");
}

export function getIdempotencyKeyFromRequest(request: Request) {
  const key = request.headers.get("idempotency-key")?.trim();
  if (!key) {
    return null;
  }
  if (key.length < 4 || key.length > 128) {
    return null;
  }
  return key;
}

export function buildIdempotencyScopeKey(params: {
  route: string;
  workspaceId: string;
  userId: string;
  key: string;
}) {
  return [
    "idem",
    sanitizeSegment(params.route),
    sanitizeSegment(params.workspaceId),
    sanitizeSegment(params.userId),
    sanitizeSegment(params.key),
  ].join(":");
}

function responseKey(scopeKey: string) {
  return `${scopeKey}:response`;
}

function lockKey(scopeKey: string) {
  return `${scopeKey}:lock`;
}

export async function loadIdempotentResponse(scopeKey: string) {
  const raw = await getRuntimeStateAdapter().get(responseKey(scopeKey));
  if (!raw) {
    return null;
  }

  try {
    const parsed = JSON.parse(raw) as StoredIdempotentResponse;
    if (
      typeof parsed.status !== "number" ||
      typeof parsed.storedAt !== "string" ||
      parsed.body === undefined
    ) {
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

export async function acquireIdempotencyLock(
  scopeKey: string,
  ttlSeconds = DEFAULT_LOCK_TTL_SECONDS,
) {
  return getRuntimeStateAdapter().setIfAbsent(lockKey(scopeKey), "1", ttlSeconds);
}

export async function releaseIdempotencyLock(scopeKey: string) {
  await getRuntimeStateAdapter().del(lockKey(scopeKey));
}

export async function storeIdempotentResponse(
  scopeKey: string,
  response: StoredIdempotentResponse,
  ttlSeconds = DEFAULT_RESPONSE_TTL_SECONDS,
) {
  await getRuntimeStateAdapter().set(
    responseKey(scopeKey),
    JSON.stringify(response),
    ttlSeconds,
  );
}

lib/rateLimit.ts.source:
import { resetMemoryRuntimeStateForTests } from "@/lib/runtime-state/memory";
import { getRuntimeStateAdapter } from "@/lib/runtime-state";
import type { RateLimitResult } from "@/lib/runtime-state/types";

/**
 * Extract the client IP from reverse-proxy headers.
 *
 * Trust model: this function is only safe when the application sits behind a
 * trusted reverse proxy (e.g. Cloud Run / Google Cloud Load Balancer, Cloud
 * Ingress) that OVERWRITES these headers with the real client IP before
 * forwarding the request. If the application is exposed directly to the
 * internet an attacker can spoof x-forwarded-for to bypass rate limiting.
 * Do NOT use this in deployments without a trusted, header-stripping proxy.
 */
export function getClientIp(request: Request): string {
  const forwarded = request.headers.get("x-forwarded-for");
  if (forwarded) {
    // Take the leftmost (original client) IP from the comma-separated list.
    return forwarded.split(",")[0].trim();
  }

  const realIp = request.headers.get("x-real-ip");
  if (realIp) {
    return realIp;
  }

  return "unknown";
}

export async function checkRateLimit(
  clientKey: string,
  maxRequestsPerMinute: number,
  burstRequestsPer10s = 6,
): Promise<RateLimitResult> {
  return getRuntimeStateAdapter().checkRateLimit(
    clientKey,
    maxRequestsPerMinute,
    burstRequestsPer10s,
  );
}

export function resetRateLimiterForTests() {
  resetMemoryRuntimeStateForTests();
}

lib/safety.ts.source:
type SafetyInput = {
  transcript: string;
  summary: string;
  taskList: string[];
  emailDraft: string;
};

export type SafetyResult = {
  ok: boolean;
  fallbackUsed: boolean;
  issues: string[];
  normalized: {
    summary: string;
    taskList: string[];
    emailDraft: string;
  };
};

const ACTION_PREFIX_REGEX =
  /^(follow|send|schedule|share|prepare|update|create|review|confirm|draft|book|call|email|sync|investigate|deploy|monitor|document|close|assign)\b/i;

function countSentences(text: string) {
  return text
    .split(/[.!?]+/)
    .map((part) => part.trim())
    .filter(Boolean).length;
}

function hasExplicitRequest(transcript: string) {
  return /\b(please|need to|can you|could you|action item|follow up|schedule|send|prepare|share|book|draft|update|assign)\b/i.test(
    transcript,
  );
}

function extractPotentialEntities(text: string) {
  const matches = text.match(/\b[A-Z][a-z]+ [A-Z][a-z]+\b/g);
  return (matches ?? []).map((value) => value.toLowerCase());
}

function normalizeEmailDraft(emailDraft: string): {
  emailDraft: string;
  changed: boolean;
} {
  let next = emailDraft.trim();
  let changed = false;

  if (!/^subject:/i.test(next)) {
    next = `Subject: Transcript Follow-up\n\n${next}`;
    changed = true;
  }

  if (!/please review before sending\.?$/im.test(next)) {
    next = `${next}\n\nPlease review before sending.`;
    changed = true;
  }

  return { emailDraft: next, changed };
}

export function runSafetyCheck(input: SafetyInput): SafetyResult {
  const issues: string[] = [];
  let fallbackUsed = false;

  const transcript = input.transcript.trim();
  let summary = input.summary.trim();
  let taskList = input.taskList.map((item) => item.trim()).filter(Boolean);
  const emailNormalized = normalizeEmailDraft(input.emailDraft);

  if (emailNormalized.changed) {
    fallbackUsed = true;
  }

  if (!transcript) {
    issues.push("Transcript is empty.");
  }

  if (!summary) {
    issues.push("Summary is empty.");
  }

  const sentenceCount = countSentences(summary);
  if (sentenceCount > 3) {
    summary = summary
      .split(/(?<=[.!?])\s+/)
      .slice(0, 3)
      .join(" ")
      .trim();
    fallbackUsed = true;
  }

  taskList = taskList.map((item) => {
    let normalized = item;

    if (normalized.length > 140) {
      normalized = `${normalized.slice(0, 137).trim()}...`;
      fallbackUsed = true;
    }

    if (!ACTION_PREFIX_REGEX.test(normalized)) {
      normalized = `Follow up: ${normalized}`;
      fallbackUsed = true;
    }

    return normalized;
  });

  if (hasExplicitRequest(transcript) && taskList.length < 1) {
    issues.push("Transcript contains explicit requests but no action items were extracted.");
  }

  const transcriptEntities = new Set(extractPotentialEntities(transcript));
  const taskEntities = extractPotentialEntities(taskList.join("\n"));

  const foreignEntities = taskEntities.filter(
    (entity) => !transcriptEntities.has(entity),
  );

  if (foreignEntities.length > 0) {
    issues.push("Action items may introduce entities not present in the transcript.");
  }

  if (!emailNormalized.emailDraft.trim()) {
    issues.push("Email draft is empty.");
  }

  return {
    ok: issues.length === 0,
    fallbackUsed,
    issues,
    normalized: {
      summary,
      taskList,
      emailDraft: emailNormalized.emailDraft,
    },
  };
}

lib/ssrf.ts.source:
import { lookup } from "node:dns/promises";
import { isIP } from "node:net";

type ValidationResult =
  | { ok: true; url: URL }
  | { ok: false; reason: string };

function parseAllowlistHosts() {
  const configured = process.env.WEBHOOK_ALLOWLIST_HOSTS;
  if (!configured?.trim()) {
    return new Set<string>();
  }

  return new Set(
    configured
      .split(",")
      .map((entry) => entry.trim().toLowerCase())
      .filter(Boolean),
  );
}

function isAllowlistedHost(hostname: string, allowlistHosts: Set<string>) {
  if (allowlistHosts.size === 0) {
    return true;
  }

  if (allowlistHosts.has(hostname)) {
    return true;
  }

  return [...allowlistHosts].some((allowed) => hostname.endsWith(`.${allowed}`));
}

function isPrivateIpv4(address: string) {
  const parts = address.split(".").map((part) => Number.parseInt(part, 10));
  if (parts.length !== 4 || parts.some((part) => Number.isNaN(part))) {
    return true;
  }

  const [a, b] = parts;
  if (a === 10 || a === 127 || a === 0) {
    return true;
  }
  if (a === 100 && b >= 64 && b <= 127) {
    return true;
  }
  if (a === 169 && b === 254) {
    return true;
  }
  if (a === 172 && b >= 16 && b <= 31) {
    return true;
  }
  if (a === 192 && b === 168) {
    return true;
  }
  if (a === 192 && b === 0) {
    return true;
  }
  if (a === 198 && (b === 18 || b === 19)) {
    return true;
  }
  if (a >= 224) {
    return true;
  }
  return false;
}

function isPrivateIpv6(address: string) {
  const normalized = address.toLowerCase();
  if (normalized === "::1" || normalized === "::") {
    return true;
  }

  if (
    normalized.startsWith("fc") ||
    normalized.startsWith("fd") ||
    normalized.startsWith("fe8") ||
    normalized.startsWith("fe9") ||
    normalized.startsWith("fea") ||
    normalized.startsWith("feb")
  ) {
    return true;
  }

  if (normalized.startsWith("::ffff:")) {
    const embedded = normalized.slice("::ffff:".length);
    if (embedded && isIP(embedded) === 4) {
      return isPrivateIpv4(embedded);
    }
  }

  return false;
}

function isPrivateIp(address: string) {
  const family = isIP(address);
  if (family === 4) {
    return isPrivateIpv4(address);
  }
  if (family === 6) {
    return isPrivateIpv6(address);
  }
  return true;
}

function hasUnsafeHostname(hostname: string) {
  return (
    hostname === "localhost" ||
    hostname.endsWith(".local") ||
    hostname.endsWith(".internal") ||
    hostname.endsWith(".localdomain") ||
    hostname === "metadata.google.internal"
  );
}

export async function validateOutboundUrl(urlRaw: string): Promise<ValidationResult> {
  let url: URL;
  try {
    url = new URL(urlRaw);
  } catch {
    return { ok: false, reason: "Invalid URL." };
  }

  if (url.protocol !== "https:") {
    return { ok: false, reason: "Only HTTPS endpoints are allowed." };
  }

  if (url.username || url.password) {
    return { ok: false, reason: "Credentials in URL are not allowed." };
  }

  const hostname = url.hostname.trim().toLowerCase();
  if (!hostname) {
    return { ok: false, reason: "Hostname is required." };
  }

  if (hasUnsafeHostname(hostname)) {
    return { ok: false, reason: "Private hostnames are not allowed." };
  }

  const allowlistHosts = parseAllowlistHosts();
  if (!isAllowlistedHost(hostname, allowlistHosts)) {
    return { ok: false, reason: "Host is not in webhook allowlist." };
  }

  if (isIP(hostname) !== 0 && isPrivateIp(hostname)) {
    return { ok: false, reason: "Private or reserved IP addresses are blocked." };
  }

  try {
    const resolved = await lookup(hostname, { all: true, verbatim: true });
    if (!resolved.length) {
      return { ok: false, reason: "Hostname resolution failed." };
    }

    for (const entry of resolved) {
      if (isPrivateIp(entry.address)) {
        return { ok: false, reason: "Resolved to private or reserved IP." };
      }
    }
  } catch {
    return { ok: false, reason: "Hostname resolution failed." };
  }

  return {
    ok: true,
    url,
  };
}

lib/verifier.ts.source:
import type { VerifierPolicy } from "@/lib/config";
import type { VerifierReport } from "@/lib/session-meta";

type VerifierInput = {
  transcript: string;
  summary: string;
  taskList: string[];
  emailDraft: string;
  policy: VerifierPolicy;
};

type VerifierOutput = {
  report: VerifierReport;
  repaired: {
    summary: string;
    taskList: string[];
    emailDraft: string;
  };
};

function tokenize(text: string) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .map((token) => token.trim())
    .filter((token) => token.length > 2);
}

function tokenWindows(tokens: string[], size = 4) {
  const windows = new Set<string>();
  if (tokens.length === 0) {
    return windows;
  }

  if (tokens.length <= size) {
    windows.add(tokens.join(" "));
    return windows;
  }

  for (let index = 0; index <= tokens.length - size; index += 1) {
    windows.add(tokens.slice(index, index + size).join(" "));
  }

  return windows;
}

const ACTION_VERBS = new Set([
  "send",
  "schedule",
  "follow",
  "review",
  "prepare",
  "confirm",
  "update",
  "share",
  "call",
  "email",
  "draft",
  "assign",
  "check",
  "resolve",
  "investigate",
  "deliver",
  "complete",
  "track",
  "create",
  "finalize",
]);

function extractEntityTokens(text: string) {
  const entities = text.match(/\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)?\b/g) ?? [];
  return entities.map((entity) => entity.toLowerCase());
}

function sentenceList(text: string) {
  return text
    .split(/(?<=[.!?])\s+/)
    .map((line) => line.trim())
    .filter(Boolean);
}

function overlapRatio(sourceTokens: Set<string>, line: string) {
  const tokens = tokenize(line);
  if (!tokens.length) {
    return 0;
  }

  const hits = tokens.filter((token) => sourceTokens.has(token)).length;
  return hits / tokens.length;
}

export function runGroundingVerifier(input: VerifierInput): VerifierOutput {
  const transcriptTokenList = tokenize(input.transcript);
  const transcriptTokens = new Set(transcriptTokenList);
  const transcriptWindows = tokenWindows(transcriptTokenList, 4);
  const transcriptEntityTokens = new Set(extractEntityTokens(input.transcript));
  const flags: string[] = [];

  let score = 100;
  let summary = input.summary.trim();
  let taskList = input.taskList.map((task) => task.trim()).filter(Boolean);
  let emailDraft = input.emailDraft.trim();

  if (!summary) {
    flags.push("summary_empty");
    score -= 40;
  }

  if (!taskList.length && /\b(please|need to|can you|follow up|schedule|send)\b/i.test(input.transcript)) {
    flags.push("missing_requested_task");
    score -= 30;
  }

  const summarySentences = sentenceList(summary);
  const lowOverlapSummarySentences = summarySentences.filter(
    (sentence) => overlapRatio(transcriptTokens, sentence) < 0.2,
  );
  if (lowOverlapSummarySentences.length > 0) {
    flags.push("summary_low_overlap");
    score -= Math.min(30, lowOverlapSummarySentences.length * 10);
  }

  const lowOverlapTasks = taskList.filter((task) => overlapRatio(transcriptTokens, task) < 0.2);
  if (lowOverlapTasks.length > 0) {
    flags.push("task_low_overlap");
    score -= Math.min(40, lowOverlapTasks.length * 12);
  }

  const nonActionTasks = taskList.filter((task) => {
    const firstToken = tokenize(task)[0];
    if (!firstToken) {
      return true;
    }
    if (ACTION_VERBS.has(firstToken)) {
      return false;
    }
    return !/^(to|please)$/i.test(firstToken);
  });
  if (nonActionTasks.length > 0) {
    flags.push("task_non_actionable");
    score -= Math.min(20, nonActionTasks.length * 6);
  }

  const outputLines = [summary, ...taskList, emailDraft]
    .join("\n")
    .split(/\n+/)
    .map((line) => line.trim())
    .filter(Boolean);
  const lowWindowLines = outputLines.filter((line) => {
    const tokens = tokenize(line);
    if (tokens.length < 4) {
      return false;
    }
    const windows = tokenWindows(tokens, 4);
    if (!windows.size) {
      return false;
    }

    let matches = 0;
    for (const window of windows) {
      if (transcriptWindows.has(window)) {
        matches += 1;
      }
    }
    return matches / windows.size < 0.1;
  });
  if (lowWindowLines.length > 0) {
    flags.push("token_window_mismatch");
    score -= Math.min(20, lowWindowLines.length * 6);
  }

  const outputEntities = new Set([
    ...extractEntityTokens(summary),
    ...extractEntityTokens(taskList.join("\n")),
    ...extractEntityTokens(emailDraft),
  ]);
  const leakedEntities = [...outputEntities].filter(
    (entity) => !transcriptEntityTokens.has(entity),
  );
  if (leakedEntities.length > 0) {
    flags.push("entity_leakage");
    flags.push(`entity_mismatch:${leakedEntities.slice(0, 3).join(",")}`);
    score -= Math.min(30, leakedEntities.length * 6);
  }

  if (!/please review before sending\.?$/im.test(emailDraft)) {
    flags.push("email_footer_missing");
    score -= 10;
  }

  if (!/^subject:/i.test(emailDraft)) {
    flags.push("email_subject_missing");
    score -= 15;
  }

  if (input.policy === "repair" && flags.length > 0) {
    if (!summary || lowOverlapSummarySentences.length > 0) {
      summary =
        sentenceList(input.transcript).slice(0, 2).join(" ") ||
        "Summary unavailable due to grounding repair.";
    }

    if (lowOverlapTasks.length > 0) {
      taskList = taskList.filter((task) => overlapRatio(transcriptTokens, task) >= 0.2);
      if (!taskList.length && /\b(please|need to|can you|follow up|schedule|send)\b/i.test(input.transcript)) {
        taskList = ["Follow up on explicitly requested items from transcript."];
      }
    }
    if (nonActionTasks.length > 0) {
      taskList = taskList.map((task) => {
        const firstToken = tokenize(task)[0];
        if (firstToken && ACTION_VERBS.has(firstToken)) {
          return task;
        }
        return `Follow up: ${task}`;
      });
    }

    if (!/^subject:/i.test(emailDraft)) {
      emailDraft = `Subject: Transcript Follow-up\n\n${emailDraft}`;
    }
    if (!/please review before sending\.?$/im.test(emailDraft)) {
      emailDraft = `${emailDraft}\n\nPlease review before sending.`;
    }

    score = Math.max(score, 75);
  }

  const ok = score >= 70 && !flags.includes("summary_empty");

  return {
    report: {
      ok,
      score: Math.max(0, Math.min(100, score)),
      flags,
      policy: input.policy,
    },
    repaired: {
      summary,
      taskList,
      emailDraft,
    },
  };
}

lib/rbac.ts.source:
import { NextResponse } from "next/server";

import type { SessionData, SessionRole } from "@/lib/auth";

const ROLE_RANK: Record<SessionRole, number> = {
  viewer: 0,
  agent: 1,
  admin: 2,
  owner: 3,
};

export function hasRole(
  currentRole: SessionRole,
  requiredRoles: SessionRole[],
) {
  const currentRank = ROLE_RANK[currentRole] ?? 0;
  return requiredRoles.some((role) => currentRank >= ROLE_RANK[role]);
}

export function forbiddenResponse(requestId: string, detailsCode = "RBAC_FORBIDDEN") {
  return NextResponse.json(
    {
      error: {
        code: "FORBIDDEN",
        detailsCode,
        message: "You do not have permission for this action.",
        requestId,
      },
    },
    { status: 403 },
  );
}

export function ensureRole(
  session: SessionData,
  requiredRoles: SessionRole[],
  requestId: string,
  detailsCode?: string,
) {
  if (!hasRole(session.role, requiredRoles)) {
    return forbiddenResponse(requestId, detailsCode);
  }

  return null;
}

